interface User {
  readonly id: number;
  name: string;
  age: number;
  email?: string;
}

interface Admin extends User {
  role: "admin";
  permissions: string[];
}

const admin: Admin = {
  id: 1,
  name: "Борис",
  age: 30,
  role: "admin",
  permissions: ["users:read", "users:write"],
};

// Хотим обернуть любые данные в «ответ API»
interface UserResponse {
  data: User;
  status: number;
  timestamp: Date;
}

interface AdminResponse {
  data: Admin;
  status: number;
  timestamp: Date;
}

// Дублирование! Отличается только тип data

interface ApiResponse<T> {
  data: T;
  status: number;
  timestamp: Date;
}

const userResponse: ApiResponse<User> = {
  data: { id: 1, name: "Анна", age: 25 },
  status: 200,
  timestamp: new Date(),
};

const adminResponse: ApiResponse<Admin> = {
  data: { id: 2, name: "Борис", age: 30, role: "admin", permissions: [] },
  status: 200,
  timestamp: new Date(),
};

function fetchUser(id: number): [User | null, string | null] {
  try {
    const user: User = { id, name: "Анна", age: 25 };
    return [user, null];           // Успех: данные + нет ошибки
  } catch (e) {
    return [null, "Не найден"];    // Ошибка: нет данных + сообщение
  }
}

const [user, error] = fetchUser(1);
// user: User | null
// error: string | null

if (error) {
  console.log(`Ошибка: ${error}`);
} else {
  console.log(`Пользователь: ${user!.name}`);
}
